# services/fastf1_service.py
files['backend/app/services/fastf1_service.py'] = '''"""Core FastF1 wrapper service for Pitwall.ai."""\nimport fastf1\nimport pandas as pd\nfrom typing import Any\nfrom app.config import CACHE_DIR, CURRENT_SEASON\n\n\nclass FastF1Service:\n    """Service class wrapping FastF1 library for F1 data access."""\n\n    def __init__(self):\n        """Initialize FastF1 with caching enabled."""\n        fastf1.Cache.enable_cache(CACHE_DIR)\n\n    def get_schedule(self, year: int) -> list[dict[str, Any]]:\n        """Get the full race schedule for a season."""\n        schedule = fastf1.get_event_schedule(year)\n        races = []\n        for _, event in schedule.iterrows():\n            if event.get("EventFormat", "") == "testing":\n                continue\n            races.append({\n                "round": int(event.get("RoundNumber", 0)),\n                "raceName": str(event.get("EventName", "")),\n                "country": str(event.get("Country", "")),\n                "location": str(event.get("Location", "")),\n                "eventDate": str(event.get("EventDate", "")),\n                "eventFormat": str(event.get("EventFormat", "")),\n            })\n        return [r for r in races if r["round"] > 0]\n\n    def _load_session(self, year: int, round_num: int, session_type: str):\n        """Load a FastF1 session with data."""\n        session = fastf1.get_session(year, round_num, session_type)\n        session.load()\n        return session\n\n    def get_race_results(self, year: int, round_num: int) -> list[dict[str, Any]]:\n        """Get race results for a specific round."""\n        session = self._load_session(year, round_num, "R")\n        results = session.results\n        output = []\n        for _, row in results.iterrows():\n            output.append({\n                "position": _safe_int(row.get("Position")),\n                "driverNumber": str(row.get("DriverNumber", "")),\n                "abbreviation": str(row.get("Abbreviation", "")),\n                "fullName": str(row.get("FullName", "")),\n                "team": str(row.get("TeamName", "")),\n                "teamColor": str(row.get("TeamColor", "")),\n                "gridPosition": _safe_int(row.get("GridPosition")),\n                "status": str(row.get("Status", "")),\n                "points": float(row.get("Points", 0)),\n                "time": str(row.get("Time", "")),\n            })\n        return output\n\n    def get_drivers(self, year: int) -> list[dict[str, Any]]:\n        """Get all drivers for a season using Ergast API."""\n        try:\n            ergast = fastf1.ergast.Ergast()\n            driver_info = ergast.get_driver_info(season=year)\n            df = driver_info.content[0]\n            drivers = []\n            for _, row in df.iterrows():\n                drivers.append({\n                    "driverId": str(row.get("driverId", "")),\n                    "givenName": str(row.get("givenName", "")),\n                    "familyName": str(row.get("familyName", "")),\n                    "nationality": str(row.get("nationality", "")),\n                    "permanentNumber": str(row.get("permanentNumber", "")),\n                    "code": str(row.get("code", "")),\n                })\n            return drivers\n        except Exception:\n            return []\n\n    def get_driver_stats(self, driver_id: str, year: int) -> dict[str, Any]:\n        """Get aggregated season stats for a driver."""\n        try:\n            ergast = fastf1.ergast.Ergast()\n            standings = ergast.get_driver_standings(season=year)\n            df = standings.content[0]\n            driver_row = df[df["driverId"] == driver_id]\n            if driver_row.empty:\n                return {"error": "Driver not found in standings"}\n            row = driver_row.iloc[0]\n            return {\n                "position": int(row.get("position", 0)),\n                "points": float(row.get("points", 0)),\n                "wins": int(row.get("wins", 0)),\n                "driverId": driver_id,\n            }\n        except Exception as e:\n            return {"error": str(e)}\n\n    def get_telemetry(\n        self, year: int, round_num: int, session_type: str, driver: str\n    ) -> dict[str, Any]:\n        """Get telemetry data for a driver in a session."""\n        session = self._load_session(year, round_num, session_type)\n        laps = session.laps.pick_drivers(driver)\n\n        # Get fastest lap telemetry\n        fastest = laps.pick_fastest()\n        telemetry = fastest.get_telemetry()\n\n        # Downsample telemetry to reduce payload size (every 5th point)\n        sampled = telemetry.iloc[::5]\n\n        lap_times = []\n        for _, lap in laps.iterrows():\n            lt = lap.get("LapTime")\n            lap_times.append({\n                "lapNumber": int(lap.get("LapNumber", 0)),\n                "lapTime": str(lt) if pd.notna(lt) else None,\n                "lapTimeSeconds": lt.total_seconds() if pd.notna(lt) else None,\n                "sector1": _td_to_seconds(lap.get("Sector1Time")),\n                "sector2": _td_to_seconds(lap.get("Sector2Time")),\n                "sector3": _td_to_seconds(lap.get("Sector3Time")),\n                "compound": str(lap.get("Compound", "")),\n                "tyreLife": _safe_float(lap.get("TyreLife")),\n                "position": _safe_int(lap.get("Position")),\n            })\n\n        return {\n            "lapTimes": lap_times,\n            "fastestLap": {\n                "lapNumber": int(fastest.get("LapNumber", 0)),\n                "lapTime": str(fastest.get("LapTime", "")),\n                "compound": str(fastest.get("Compound", "")),\n            },\n            "telemetrySample": {\n                "speed": sampled["Speed"].tolist(),\n                "throttle": sampled["Throttle"].tolist(),\n                "brake": sampled["Brake"].astype(int).tolist(),\n                "gear": sampled["nGear"].tolist(),\n                "rpm": sampled["RPM"].tolist(),\n                "drs": sampled["DRS"].tolist(),\n                "distance": sampled["Distance"].tolist() if "Distance" in sampled.columns else [],\n            },\n        }\n\n\ndef _safe_int(val) -> int:\n    """Safely convert to int."""\n    try:\n        if pd.isna(val):\n            return 0\n        return int(val)\n    except (ValueError, TypeError):\n        return 0\n\n\ndef _safe_float(val) -> float:\n    """Safely convert to float."""\n    try:\n        if pd.isna(val):\n            return 0.0\n        return float(val)\n    except (ValueError, TypeError):\n        return 0.0\n\n\ndef _td_to_seconds(val) -> float | None:\n    """Convert timedelta to seconds."""\n    try:\n        if pd.isna(val):\n            return None\n        return val.total_seconds()\n    except (AttributeError, TypeError):\n        return None\n'''

# services/prediction_service.py
files['backend/app/services/prediction_service.py'] = '''"""ML-based race prediction service for Pitwall.ai."""\nfrom typing import Any\n\n\nclass PredictionService:\n    """\n    Race prediction service using historical performance data.\n\n    Currently uses a heuristic model based on qualifying and recent race\n    performance. Future versions will integrate scikit-learn / XGBoost\n    models trained on historical FastF1 data.\n    """\n\n    # Default 2025 grid with approximate strength ratings\n    DRIVER_RATINGS = {\n        "VER": {"name": "Max Verstappen", "team": "Red Bull Racing", "rating": 0.95},\n        "NOR": {"name": "Lando Norris", "team": "McLaren", "rating": 0.92},\n        "LEC": {"name": "Charles Leclerc", "team": "Ferrari", "rating": 0.90},\n        "PIA": {"name": "Oscar Piastri", "team": "McLaren", "rating": 0.88},\n        "SAI": {"name": "Carlos Sainz", "team": "Williams", "rating": 0.86},\n        "HAM": {"name": "Lewis Hamilton", "team": "Ferrari", "rating": 0.89},\n        "RUS": {"name": "George Russell", "team": "Mercedes", "rating": 0.87},\n        "ANT": {"name": "Kimi Antonelli", "team": "Mercedes", "rating": 0.82},\n        "ALO": {"name": "Fernando Alonso", "team": "Aston Martin", "rating": 0.84},\n        "STR": {"name": "Lance Stroll", "team": "Aston Martin", "rating": 0.75},\n        "GAS": {"name": "Pierre Gasly", "team": "Alpine", "rating": 0.80},\n        "DOO": {"name": "Jack Doohan", "team": "Alpine", "rating": 0.72},\n        "TSU": {"name": "Yuki Tsunoda", "team": "RB", "rating": 0.79},\n        "LAW": {"name": "Liam Lawson", "team": "Red Bull Racing", "rating": 0.78},\n        "ALB": {"name": "Alexander Albon", "team": "Williams", "rating": 0.81},\n        "HUL": {"name": "Nico Hulkenberg", "team": "Sauber", "rating": 0.77},\n        "BOR": {"name": "Gabriel Bortoleto", "team": "Sauber", "rating": 0.71},\n        "OCO": {"name": "Esteban Ocon", "team": "Haas", "rating": 0.78},\n        "BEA": {"name": "Oliver Bearman", "team": "Haas", "rating": 0.73},\n        "HAD": {"name": "Isack Hadjar", "team": "RB", "rating": 0.70},\n    }\n\n    def predict_race(self, year: int, round_num: int) -> list[dict[str, Any]]:\n        """\n        Predict finishing order for a race.\n\n        Uses driver ratings with small random variance to simulate\n        prediction uncertainty. In production, this would use an\n        XGBoost model trained on qualifying gaps, practice pace,\n        historical circuit performance, and weather conditions.\n        """\n        import random\n        random.seed(year * 100 + round_num)\n\n        predictions = []\n        for code, info in self.DRIVER_RATINGS.items():\n            noise = random.gauss(0, 0.05)\n            score = info["rating"] + noise\n            predictions.append({\n                "driver": code,\n                "name": info["name"],\n                "team": info["team"],\n                "score": round(score, 4),\n            })\n\n        predictions.sort(key=lambda x: x["score"], reverse=True)\n\n        result = []\n        for i, pred in enumerate(predictions, 1):\n            confidence = max(0.4, min(0.99, pred["score"]))\n            result.append({\n                "position": i,\n                "driver": pred["driver"],\n                "name": pred["name"],\n                "team": pred["team"],\n                "confidence": round(confidence * 100, 1),\n            })\n        return result\n'''

# services/data_processor.py
files['backend/app/services/data_processor.py'] = '''"""Data transformation utilities for Pitwall.ai."""\nimport pandas as pd\nfrom typing import Any\n\n\ndef format_lap_time(td) -> str:\n    """Format a timedelta lap time to M:SS.mmm string."""\n    if pd.isna(td):\n        return "--"\n    total_seconds = td.total_seconds()\n    minutes = int(total_seconds // 60)\n    seconds = total_seconds % 60\n    return f"{minutes}:{seconds:06.3f}"\n\n\ndef calculate_gap(leader_time, driver_time) -> str:\n    """Calculate gap between two lap times."""\n    if pd.isna(leader_time) or pd.isna(driver_time):\n        return "--"\n    gap = (driver_time - leader_time).total_seconds()\n    if gap == 0:\n        return "LEADER"\n    return f"+{gap:.3f}s"\n\n\ndef extract_tire_strategy(laps_df: pd.DataFrame, driver: str) -> list[dict[str, Any]]:\n    """Extract tire strategy (stints) for a driver."""\n    driver_laps = laps_df[laps_df["Driver"] == driver]\n    stints = (\n        driver_laps.groupby(["Stint", "Compound"])\n        .agg({\n            "TyreLife": "max",\n            "LapNumber": ["min", "max"],\n        })\n        .reset_index()\n    )\n    stints.columns = ["stint", "compound", "tyreLife", "startLap", "endLap"]\n    return stints.to_dict(orient="records")\n\n\ndef aggregate_sector_times(laps_df: pd.DataFrame, driver: str) -> dict[str, Any]:\n    """Get best and average sector times for a driver."""\n    driver_laps = laps_df[laps_df["Driver"] == driver]\n    accurate = driver_laps[driver_laps["IsAccurate"] == True]\n\n    def _sec(td):\n        return td.total_seconds() if pd.notna(td) else None\n\n    return {\n        "bestSector1": _sec(accurate["Sector1Time"].min()),\n        "bestSector2": _sec(accurate["Sector2Time"].min()),\n        "bestSector3": _sec(accurate["Sector3Time"].min()),\n        "avgSector1": _sec(accurate["Sector1Time"].mean()),\n        "avgSector2": _sec(accurate["Sector2Time"].mean()),\n        "avgSector3": _sec(accurate["Sector3Time"].mean()),\n    }\n\n\nCOMPOUND_COLORS = {\n    "SOFT": "#FF3333",\n    "MEDIUM": "#FFD700",\n    "HARD": "#FFFFFF",\n    "INTERMEDIATE": "#39B54A",\n    "WET": "#0067FF",\n}\n'''

